  1	import React, { FC, useMemo } from 'react';
  2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
  3	import classNames from 'classnames';
  4	
  5	import useVirtualMachineInstanceTypes from '@catalog/CreateFromInstanceTypes/state/hooks/useVirtualMachineInstanceTypes';
  6	import { VirtualMachineInstancetypeModelRef } from '@kubevirt-ui/kubevirt-api/console';
  7	import VirtualMachineClusterInstancetypeModel, {
  8	  VirtualMachineClusterInstancetypeModelRef,
  9	} from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineClusterInstancetypeModel';
 10	import { ALL_NAMESPACES } from '@kubevirt-utils/hooks/constants';
 11	import useIsSearchPage from '@kubevirt-utils/hooks/useIsSearchPage';
 12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 13	import { ListPageProps } from '@kubevirt-utils/utils/types';
 14	import { isEmpty } from '@kubevirt-utils/utils/utils';
 15	import { ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 16	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 17	
 18	import InstancetypeCreateButton from './components/InstancetypeCreateButton/InstancetypeCreateButton';
 19	import ClusterInstancetypeList from './ClusterInstancetypeList';
 20	import UserInstancetypeList from './UserInstancetypeList';
 21	
 22	import '@kubevirt-utils/styles/list-managment-group.scss';
 23	
 24	const InstanceTypePage: FC<ListPageProps> = (props) => {
 25	  const { t } = useKubevirtTranslation();
 26	  const navigate = useNavigate();
 27	  const location = useLocation();
 28	  const activeNamespace = props?.namespace ?? ALL_NAMESPACES;
 29	
 30	  const isSearchPage = useIsSearchPage();
 31	
 32	  const activeTabKey = useMemo(
 33	    () => (location?.pathname.includes(VirtualMachineClusterInstancetypeModel.kind) ? 0 : 1),
 34	    [location?.pathname],
 35	  );
 36	  const [instanceTypes, loaded, loadError] = useVirtualMachineInstanceTypes(
 37	    props?.fieldSelector,
 38	    props?.selector,
 39	    true,
 40	  );
 41	
 42	  const urlUserInstancetypes = useMemo(
 43	    () =>
 44	      activeNamespace === ALL_NAMESPACES
 45	        ? `/k8s/all-namespaces/${VirtualMachineInstancetypeModelRef}`
 46	        : `/k8s/ns/${activeNamespace}/${VirtualMachineInstancetypeModelRef}`,
 47	    [activeNamespace],
 48	  );
 49	
 50	  if (isSearchPage) {
 51	    const searchParams = new URLSearchParams(location?.search);
 52	
 53	    const kindSearched = searchParams.get('kind');
 54	    return kindSearched === VirtualMachineClusterInstancetypeModelRef ? (
 55	      <ClusterInstancetypeList {...props} />
 56	    ) : (
 57	      <UserInstancetypeList {...props} />
 58	    );
 59	  }
 60	
 61	  return (
 62	    <>
 63	      <div className={classNames({ 'list-header-spacer': activeTabKey === 0 })}>
 64	        <ListPageHeader
 65	          title={
 66	            activeTabKey === 0
 67	              ? t('VirtualMachineClusterInstanceTypes')
 68	              : t('VirtualMachineInstanceTypes')
 69	          }
 70	        >
 71	          {(activeTabKey === 0 || (!isEmpty(instanceTypes) && loaded && !loadError)) && (
 72	            <InstancetypeCreateButton namespace={activeNamespace} />
 73	          )}
 74	        </ListPageHeader>
 75	      </div>
 76	      <Tabs
 77	        onSelect={(_, tabIndex: number | string) => {
 78	          navigate(
 79	            tabIndex === 0
 80	              ? `/k8s/cluster/${VirtualMachineClusterInstancetypeModelRef}`
 81	              : urlUserInstancetypes,
 82	          );
 83	        }}
 84	        activeKey={activeTabKey}
 85	        style={{ flexShrink: 0 }}
 86	      >
 87	        <Tab
 88	          title={
 89	            <TabTitleText data-test="cluster-instancetype-tab">
 90	              {t('Cluster InstanceTypes')}
 91	            </TabTitleText>
 92	          }
 93	          eventKey={0}
 94	        >
 95	          <ClusterInstancetypeList {...props} />
 96	        </Tab>
 97	        <Tab
 98	          title={
 99	            <TabTitleText data-test="user-instancetype-tab">{t('User InstanceTypes')}</TabTitleText>
100	          }
101	          eventKey={1}
102	        >
103	          <UserInstancetypeList {...props} />
104	        </Tab>
105	      </Tabs>
106	    </>
107	  );
108	};
109	
110	export default InstanceTypePage;

